/**
 * capify
 * String case transformation library.
 */

export function toSentenceCase(str: string): string;
export function toLowerCase(str: string): string;
export function toUpperCase(str: string): string;
export function toCapitalizeCase(str: string): string;
export function toAlternatingCase(str: string): string;

declare const _default: {
    toSentenceCase: typeof toSentenceCase;
    toLowerCase: typeof toLowerCase;
    toUpperCase: typeof toUpperCase;
    toCapitalizeCase: typeof toCapitalizeCase;
    toAlternatingCase: typeof toAlternatingCase;
};

export default _default;
